def maxStudents(seats):
    m, n = len(seats), len(seats[0])
    row_masks = []
    for row in seats:
        mask = 0
        for i, char in enumerate(row):
            if char == '.': mask |= (1 << i)
        row_masks.append(mask)
    dp = [-1] * (1 << n)
    dp[0] = 0
    for row in range(m):
        new_dp = [-1] * (1 << n)
        for mask in range(1 << n):
            if (mask & row_masks[row]) == mask and not (mask & (mask << 1)):
                cnt = bin(mask).count('1')
                for prev_mask in range(1 << n):
                    if dp[prev_mask] != -1 and not (mask & (prev_mask << 1)) and not (mask & (prev_mask >> 1)):
                        new_dp[mask] = max(new_dp[mask], dp[prev_mask] + cnt)
        dp = new_dp
    return max(dp)

